def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.3:
            score += (0.3 - ratio) * 20
            for k in range(1, 5):
                score += np.sin(ratio * k * np.pi) * 2
            if capacity % 2 == 0:
                score -= 1
            else:
                score += 1
        elif 0.3 <= ratio < 0.7:
            for m in range(1, 4):
                score += (ratio ** m) * (5 - m)
            if int(capacity) % 3 == 0:
                score -= 2
            if item > capacity / 2:
                score += 3
        elif 0.7 <= ratio <= 1:
            score += np.log1p(ratio * 10) * 10
            for p in range(1, int(item)+1):
                if p * p > capacity:
                    break
                if capacity % p == 0:
                    score -= (p / 10)
        else:
            overload = ratio - 1
            score += overload ** 3 * 50
            for q in range(1, 5):
                score += (-1) ** q * overload * q * 3
            if capacity < item * 1.1:
                score += 20
            elif capacity < item * 2:
                score += 5
            else:
                score -= 10
        if score < 0:
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        priorities[np.isinf(priorities)] = max_priority + 50
    else:
        priorities[:] = 1000
    return priorities
